| MCP:kEIJff | function mockXHR() {
| MCP:kEIJff |   // mock patch
| MCP:kEIJff |   // https://github.com/nuysoft/Mock/issues/300
| MCP:kEIJff |   Mock.XHR.prototype.proxy_send = Mock.XHR.prototype.send
| MCP:kEIJff |   Mock.XHR.prototype.send = function () {
| MCP:kEIJff |     if (this.custom.xhr) {
| MCP:kEIJff |       this.custom.xhr.withCredentials = this.withCredentials || false
| MCP:kEIJff | 
| MCP:kEIJff |       if (this.responseType) {
| MCP:kEIJff |         this.custom.xhr.responseType = this.responseType
| MCP:kEIJff |       }
| MCP:kEIJff |     }
| MCP:kEIJff |     this.proxy_send(...arguments)
| MCP:kEIJff |   }
| MCP:kEIJff | 
| MCP:kEIJff |   function XHR2ExpressReqWrap(respond) {
| MCP:kEIJff |     return function (options) {
| MCP:kEIJff |       let result = null
| MCP:kEIJff |       if (respond instanceof Function) {
| MCP:kEIJff |         const { body, type, url } = options
| MCP:kEIJff |         // https://expressjs.com/en/4x/api.html#req
| MCP:kEIJff |         result = respond({
| MCP:kEIJff |           method: type,
| MCP:kEIJff |           body: JSON.parse(body),
| MCP:kEIJff |           query: param2Obj(url),
| MCP:kEIJff |         })
| MCP:kEIJff |       } else {
| MCP:kEIJff |         result = respond
| MCP:kEIJff |       }
| MCP:kEIJff |       return Mock.mock(result)
| MCP:kEIJff |     }
| MCP:kEIJff |   }
| MCP:kEIJff | 
| MCP:kEIJff |   for (const i of mocks) {
| MCP:kEIJff |     Mock.mock(
| MCP:kEIJff |       new RegExp(i.url),
| MCP:kEIJff |       i.type || 'get',
| MCP:kEIJff |       XHR2ExpressReqWrap(i.response)
| MCP:kEIJff |     )
| MCP:kEIJff |   }
| MCP:kEIJff | }
| MCP:kEIJff | 
| MCP:kEIJff | module.exports = {
| MCP:kEIJff |   mocks,
| MCP:kEIJff |   mockXHR,
| MCP:kEIJff | }

